"use strict";parserFactory.register("novelingua.com",()=>new NovelinguaParser);class NovelinguaParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll(".pagelayer-text-holder a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector(".entry-content")||e.querySelector("article")}customRawDomToContentStep(e,r){this.cleanup(r)}cleanInformationNode(e){this.cleanup(e)}cleanup(e){e.querySelectorAll("*").forEach(e=>{e.removeAttribute("dir"),util.replaceSemanticInlineStylesWithTags(e,!0),e.id?.startsWith("docs-internal-guid-")&&e.removeAttribute("id")})}extractTitleImpl(e){return e.querySelector(".pagelayer-heading-holder h2")}findChapterTitle(e){let r=e.querySelector("link[rel='canonical']").href.split("/"),t=r.pop();return""===t&&(t=r.pop()),t=t.split("-").map(e=>e.charAt(0).toUpperCase()+e.slice(1)).join(" "),t}findCoverImageUrl(e){let r=e.querySelector("img.pagelayer-img");return null===r?r:r.src}removeUnwantedElementsFromContentElement(e){util.removeElements(e.querySelectorAll("style, .pagelayer-btn-holder, .pagelayer-share, .pagelayer-image_slider, .pagelayer-embed")),super.removeUnwantedElementsFromContentElement(e)}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".entry-content .pagelayer-text-holder")]}}